<?php
 namespace WPAICG\Core\Providers\Traits; if (!defined('ABSPATH')) { exit; } trait ChatCompletionsSSEParserTrait { public function parse_sse_chunk(string $sse_chunk, string &$current_buffer): array { $current_buffer .= $sse_chunk; $result = ['delta' => null, 'usage' => null, 'is_error' => false, 'is_warning' => false, 'is_done' => false]; while (($line_end_pos = strpos($current_buffer, "\n\n")) !== false) { $event_block = substr($current_buffer, 0, $line_end_pos); $current_buffer = substr($current_buffer, $line_end_pos + 2); $event_data_json = null; $event_type = 'message'; foreach (explode("\n", $event_block) as $line) { $line = rtrim($line, "\r"); if (empty($line) || strpos($line, ':') === false) continue; [$field, $value] = explode(':', $line, 2); $field = trim($field); $value = trim($value); if ($field === 'data') { $event_data_json = $value; break; } } if ($event_data_json === '[DONE]') { $result['is_done'] = true; continue; } if ($event_data_json) { $decoded = json_decode($event_data_json, true); if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) { if (isset($decoded['error'])) { $result['delta'] = $this->parse_error_response($decoded, 500); $result['is_error'] = true; return $result; } if (isset($decoded['usage']) && is_array($decoded['usage'])) { $result['usage'] = [ 'input_tokens' => $decoded['usage']['prompt_tokens'] ?? 0, 'output_tokens' => $decoded['usage']['completion_tokens'] ?? 0, 'total_tokens' => $decoded['usage']['total_tokens'] ?? 0, 'provider_raw' => $decoded['usage'], ]; if (!isset($decoded['choices'][0]['delta']['content'])) { } } if (isset($decoded['choices'][0]['delta']['content'])) { $delta_text = $decoded['choices'][0]['delta']['content']; if ($result['delta'] === null) { $result['delta'] = ''; } $result['delta'] .= $delta_text; } if (isset($decoded['choices'][0]['finish_reason'])) { $finish_reason = $decoded['choices'][0]['finish_reason']; if ($finish_reason === 'content_filter') { if ($result['delta'] === null) { $result['delta'] = ''; } $result['delta'] .= sprintf(' (%s)', __('Warning: Content Filtered', 'gpt3-ai-content-generator')); $result['is_warning'] = true; } elseif ($finish_reason !== null && $finish_reason !== 'stop') { } } } } } return $result; } }